namespace StyleCop.Analyzers.Test.CSharp6
{
    using System.Threading;
    using System.Threading.Tasks;
    using Microsoft.CodeAnalysis.Testing;
    using Xunit;
    using static StyleCop.Analyzers.Test.CSharp6.Verifiers.StyleCopDiagnosticVerifier<TestHelper.ExclusionTestAnalyzer>;

    /// <summary>
    /// Unit tests for testing exclusion of auto generated files.
    /// </summary>
    public class ExclusionTests
    {
        /// <summary>
        /// Gets the statements that will be used in the theory test cases.
        /// </summary>
        /// <value>
        /// The statements that will be used in the theory test cases.
        /// </value>
        public static TheoryData<string, string> ShouldBeExcluded { get; } = new TheoryData<string, string>()
        {
            { "Test.cs", string.Empty },
            { "Test.cs", "   " },
            { "Test.cs", "\r\n\r\n" },
            { "Test.cs", "\t" },
            { "Test.designer.cs", "class Foo { }" },
            { "Test.cs", "// <auto-generated" },
            { "Test.cs", "// <autogenerated" },
        };

        /// <summary>
        /// Gets the statements that will be used in the theory test cases.
        /// </summary>
        /// <value>
        /// The statements that will be used in the theory test cases.
        /// </value>
        public static TheoryData<string, string> ShouldNotBeExcluded { get; } = new TheoryData<string, string>()
        {
            { "Test.designerr.cs", "class Foo { }" },
            { "Test.cs", "// <auto--generated" },
            { "Test.cs", "/// <auto-generated" },
            { "Test.cs", "\t\r\n class Foo { }" },
        };

        /// <summary>
        /// Verifies that the source file is excluded from analysis.
        /// </summary>
        /// <param name="filename">The filename.</param>
        /// <param name="testCode">The code to test.</param>
        /// <returns>A <see cref="Task"/> representing the asynchronous unit test.</returns>
        [Theory]
        [MemberData(nameof(ShouldBeExcluded))]
        public async Task TestIsExcludedAsync(string filename, string testCode)
        {
            await new CSharpTest
            {
                TestSources =
                {
                    (filename, testCode),
                },
            }.RunAsync(CancellationToken.None).ConfigureAwait(true);
        }

        /// <summary>
        /// Verifies that the source file is not excluded from analysis.
        /// </summary>
        /// <param name="filename">The filename.</param>
        /// <param name="testCode">The code to test.</param>
        /// <returns>A <see cref="Task"/> representing the asynchronous unit test.</returns>
        [Theory]
        [MemberData(nameof(ShouldNotBeExcluded))]
        public async Task TestIsNotExcludedAsync(string filename, string testCode)
        {
            var result = Diagnostic().WithLocation(filename, 1, 1);

            var test = new CSharpTest
            {
                TestSources =
                {
                    (filename, testCode),
                },
                ExpectedDiagnostics =
                {
                    result,
                },
            };

            test.TestBehaviors |= TestBehaviors.SkipSuppressionCheck;
            await test.RunAsync(CancellationToken.None).ConfigureAwait(true);
        }
    }
}
